use rsa::{BigUint, Pkcs1v15Sign, RsaPublicKey};
use sha1::Sha1;

use crate::{Error, Header};

const PIRS_RETAIL: &str = "";
const LIVE_RETAIL: &str = "";
const PIRS_DEVKIT: &str = "";
const LIVE_DEVKIT: &str = "";

pub(crate) fn verify_header(
    header: &Header,
    digest: &[u8; 20],
) -> Result<Option<&'static str>, Error> {
    if !header.kind.is_live_or_pirs() {
        return Ok(Some("console signed"));
    }
    let mut signature = header
        .signature
        .get(..0x100)
        .ok_or_else(|| Error::Crypto("truncated header signature".into()))?
        .to_vec();
    signature.reverse();

    let candidates: [(&str, &str); 4] = [
        ("LIVE", LIVE_RETAIL),
        ("PIRS", PIRS_RETAIL),
        ("LIVE-devkit", LIVE_DEVKIT),
        ("PIRS-devkit", PIRS_DEVKIT),
    ];
    for (name, encoded) in candidates {
        let key = decode_hex(encoded)?;
        let exponent = BigUint::from_bytes_be(&key[4..8]);
        let mut modulus = key[0x10..0x110].to_vec();
        for word in modulus.chunks_exact_mut(8) {
            word.reverse();
        }
        let public_key = RsaPublicKey::new(BigUint::from_bytes_be(&modulus), exponent)
            .map_err(|error| Error::Crypto(error.to_string()))?;
        if public_key
            .verify(Pkcs1v15Sign::new::<Sha1>(), digest, &signature)
            .is_ok()
        {
            return Ok(Some(name));
        }
    }
    Ok(None)
}

fn decode_hex(value: &str) -> Result<Vec<u8>, Error> {
    if value.len() % 2 != 0 {
        return Err(Error::Crypto("odd-length public key".into()));
    }
    value
        .as_bytes()
        .chunks_exact(2)
        .map(|pair| {
            let high = hex_nibble(pair[0])?;
            let low = hex_nibble(pair[1])?;
            Ok((high << 4) | low)
        })
        .collect()
}

fn hex_nibble(value: u8) -> Result<u8, Error> {
    match value {
        b'0'..=b'9' => Ok(value - b'0'),
        b'a'..=b'f' => Ok(value - b'a' + 10),
        b'A'..=b'F' => Ok(value - b'A' + 10),
        _ => Err(Error::Crypto("invalid public-key hex".into())),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn embedded_keys_have_xbox_rsa_length() {
        for key in [PIRS_RETAIL, LIVE_RETAIL, PIRS_DEVKIT, LIVE_DEVKIT] {
            assert_eq!(decode_hex(key).unwrap().len(), 0x110);
        }
    }
}
